THE RISK:
{
 "id": "nl-selfbuild-hotspot-hollows-geo",
 "title": "The Netherlands is CE's hyperscale self-build hotspot — its 28% geography weight counts MW that carry the least PDU content in the region",
 "narrative": "The geo split apportions tamBase by colo MW as if every megawatt carries equal PDU spend. But CBRE places ~60% of Europe's operational hyperscaler self-build capacity in Ireland, the Netherlands, Sweden and Belgium — and NL is the only CE-7 country on that list. Self-build halls are precisely where busway + OCP power-shelf architectures are set as default, and Amsterdam (70% of NL colo) is where those same hyperscale tenants lease wholesale suites. So the NL slice is disproportionately composed of substitution-leading capacity, while Germany's mix skews toward colo/enterprise halls that still buy PDUs. The model's 0.28 NL weight silently assumes PDU intensity is geography-neutral; in CE it is not, and the error concentrates in the second-largest geography node.",
 "category": "boundary",
 "targetNodes": [
  "geo.NL"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "CBRE: ~60% of Europe's operational hyperscaler self-build capacity is located in Ireland, Netherlands, Sweden and Belgium (Q4 2025) — NL is the sole CE-7 member, and European self-build is growing 24% YoY, faster than colocation's 19%",
   "refs": [
    "digest:seg-mix#c16",
    "digest:seg-mix#c14",
    "digest:seg-mix#c15"
   ]
  },
  {
   "step": "propagation",
   "text": "Self-build hyperscale halls are the architecture-setting sites for busway/shelf distribution; combined with Amsterdam's ~70% concentration of NL colo capacity absorbed heavily by hyperscale tenants, NL MW carry systematically lower discrete-PDU content per MW than DE or CH MW",
   "refs": [
    "ledger:geo.NL",
    "digest:seg-mix#c24"
   ]
  },
  {
   "step": "model-impact",
   "text": "geo.NL's 0.28 is derived purely from MW apportionment (951/3,451) with a band (0.24–0.31) that only reflects capacity-count uncertainty, not PDU-intensity variation; the PDU-euro share of NL is below its capacity share, overstating the NL slice of tamBase in absolute terms",
   "refs": [
    "ledger:geo.NL",
    "ledger:tamBase"
   ]
  }
 ],
 "whyMissable": "The geo nodes look like the model's best-sourced layer — two capacity methods, triangulated, tight bands. The hidden assumption is not in the MW counts but in the apportionment method itself: euros-per-MW is treated as constant across countries, and no source in the ledger even measures it. A team auditing the MW figures would confirm them and move on.",
 "expectedObviousness": "low",
 "falsifier": "Vendor sell-through or fit-out BOM data showing NL rack-PDU revenue per colo MW in line with the CE average (e.g., a distributor split or Omdia country table showing NL PDU intensity ≈ DE's).",
 "likelihood": {
  "value": 0.32,
  "rationale": "The self-build concentration in NL is directly sourced (CBRE) and the low-PDU-content nature of self-build halls is well documented for AI-density builds; offsetting this, Amsterdam retains a large retail-colo and enterprise base, and Dutch grid constraints slow new self-build, limiting how fast the mix shifts within 12 months. [evidence revision: The trigger (self-build concentration incl. NL, 24% vs 19% growth) is now firmly and independently corroborated, and OCP-ready/hyperscale wholesale activity in Amsterdam supports the substitution-leading character of NL capacity. This modestly strengthens the hypothesis. But the load-bearing quantitative claim (NL PDU-euro/MW below CE average) remains unverified, and the Amsterdam moratorium redirecting build to other Dutch metros partially undercuts the '70% Amsterdam' sub-premise — keeping the revision small and near the original estimate.]",
  "basis": "evidence",
  "revisedFrom": 0.3
 },
 "perturbation": [
  {
   "nodeId": "geo.NL",
   "op": "set",
   "value": 0.21,
   "note": "NL slice smaller in absolute PDU-euro terms — self-build and hyperscale-leased MW discounted for lower PDU content; not a mix-shift to other countries"
  }
 ],
 "indicators": [
  {
   "signal": "Rack-power architecture in new Amsterdam-region and North Holland build permits and fit-out tenders",
   "where": "TenderNed (Dutch national tender portal); Dutch Data Center Association 'State of the Dutch Data Centers' annual report",
   "threshold": "≥2 new NL builds specifying busway/shelf distribution as base design",
   "updates": "increases"
  },
  {
   "signal": "NL share of European hyperscaler self-build pipeline",
   "where": "CBRE European Data Centres quarterly; hyperscaler capex disclosures naming Dutch sites (Microsoft Middenmeer, Google Eemshaven expansions)",
   "threshold": "NL self-build capacity additions exceeding NL colo additions in a calendar year",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Obtain a per-country PDU-intensity read (PDU revenue per colo MW for DE vs NL) via distributor interviews or an Omdia custom cut, replacing MW-only apportionment",
   "type": "information",
   "voiNodeId": "geo.NL",
   "note": "Tests the euros-per-MW-constant assumption underlying the entire geo layer, not just NL"
  },
  {
   "action": "Weight Year-1 go-to-market toward Germany and Switzerland, whose capacity mix (colo/enterprise-heavy, self-operation-heavy) is structurally more PDU-native",
   "type": "strategic",
   "voiNodeId": null,
   "note": "Reallocates scarce pre-launch sales capacity away from the substitution-leading geography"
  }
 ],
 "evidenceStatus": "corroborated",
